<script setup lang="ts">
import { computed } from "vue";
import ArrowLeft from "~/components/icons/ArrowLeft/index.vue";
import ArrowRight from "~/components/icons/ArrowRight/index.vue";
import OutlinedButton from "../OutlinedButton/index.vue";

const props = defineProps({
  modelValue: {
    type: Number,
    default: 1,
  },
  totalPage: {
    type: Number,
    default: 0,
  },
  activePage: {
    type: Number,
    default: 1,
  },
  color: {
    type: String as () =>  'primary' | 'success' | 'info' | 'warning' |'error',
    default: 'primary'
  }
});

const emit = defineEmits(["update:model-value"]);

const page = ref<number>(1);

watch(
  () => props.modelValue,
  (value) => {
    page.value = Number(value);
  }
);

watch(page, (value) => {
  emit("update:model-value", value);
});

const visiblePage = computed(() => {
  if (props.totalPage <= 0) return [1];

  const pages = Array.from(
    { length: props.totalPage },
    (_, index) => index + 1
  );
  if (pages.length > 6) {
    let middlePages: number[] = [];
    if (props.activePage <= 2) {
      return [
        ...pages.slice(0, 3),
        -1,
        ...pages.slice(pages.length - 3, pages.length),
      ];
    } else if (props.activePage >= pages.length - 1) {
      return [
        ...pages.slice(0, 3),
        -1,
        ...pages.slice(pages.length - 3, pages.length),
      ];
    } else {
      return [
        1,
        -1,
        ...pages.slice(props.activePage - 2, props.activePage + 1),
        -1,
        pages.length,
      ];
    }
  }
  return pages;
});





const bgColor = computed(() => {
  return `bg-${props.color}-50 text-${props.color}-500`
})
</script>

<template>
  <nav class="pt-3 px-6 pb-4 w-full flex items-center justify-between">
    <OutlinedButton
      id="prevBtn"
      label="Previous"
      class="font-medium"
      :disabled="page === 1"
      @on-click="page -= 1"
      :color="color"
    >
      <template #prefix>
        <ArrowLeft size="20" class="stroke-gray-700" />
      </template>
    </OutlinedButton>

    <ul class="inline-flex h-10 text-gray-500 gap-2">
      <li
        v-for="i in visiblePage"
        :class="[
          activePage === i
            ? bgColor
            : 'hover:bg-gray-100',
          'h-10 aspect-square rounded-lg flex items-center justify-center cursor-pointer transition',
        ]"
        @click="
          () => {
            if (i != -1) page = i;
          }
        "
      >
        <span>{{ i == -1 ? "..." : i }}</span>
      </li>
    </ul>

    <OutlinedButton
      id="prevBtn"
      label="Next"
      class="font-medium"
      :disabled="page === totalPage"
      @on-click="page += 1"
       :color="color"
    >
      <template #suffix>
        <ArrowRight size="20" class="stroke-gray-700" />
      </template>
    </OutlinedButton>
  </nav>
</template>

<style scoped></style>
